async function handleRequest(request) {
  const url = new URL(request.url);
  const cacheKey = url.searchParams.get('cache_key');
  const ttl = parseInt(url.searchParams.get('ttl'));

  if (isNaN(ttl)) {
    return fetch(request);
  }

  const cacheName = 'my-cache';
  const cache = caches.open(cacheName);

  try {
    const cachedResponse = await cache.match(request);
    if (cachedResponse) {
      return cachedResponse;
    }
  } catch (error) {
    console.error('Error fetching from cache:', error);
  }

  const response = await fetch(request);

  if (!response.ok) {
    throw new Error(`HTTP error! status: ${response.status}`);
  }

  const cacheKeyWithTTL = `${cacheKey}_${ttl}`;

  try {
    await cache.put(cacheKeyWithTTL, response.clone());
  } catch (error) {
    console.error('Error caching:', error);
  }

  return response;
}